import{_ as e,o as d,c as a,a2 as o}from"./chunks/framework.y1bVONfd.js";const b=JSON.parse('{"title":"Configuration","description":"Environment variables and system settings reference","frontmatter":{"title":"Configuration","description":"Environment variables and system settings reference"},"headers":[],"relativePath":"guide/configuration.md","filePath":"guide/configuration.md"}'),r={name:"guide/configuration.md"};function n(i,t,c,l,s,h){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><p>All settings can be configured via <code>.env</code> file in the project root or through environment variables.</p><h3 id="core-settings" tabindex="-1">Core Settings <a class="header-anchor" href="#core-settings" aria-label="Permalink to &quot;Core Settings&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>SESSION_SECRET</code></td><td>Flask session encryption key</td><td>Auto-generated</td></tr><tr><td><code>DATABASE_URI</code></td><td>Database connection string</td><td><code>sqlite:///data/webrouter.db</code></td></tr><tr><td><code>REDIS_URL</code></td><td>Redis connection (optional, for caching)</td><td><code>redis://localhost:6379/0</code></td></tr><tr><td><code>FLASK_ENV</code></td><td>Runtime environment</td><td><code>production</code></td></tr><tr><td><code>TZ</code></td><td>Timezone</td><td><code>Asia/Shanghai</code></td></tr></tbody></table><h3 id="port-configuration" tabindex="-1">Port Configuration <a class="header-anchor" href="#port-configuration" aria-label="Permalink to &quot;Port Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>WR_PORT</code></td><td>Flask admin panel port</td><td><code>5050</code></td></tr><tr><td><code>WR_PROXY_PORT</code></td><td>wr-proxy gateway port</td><td><code>5051</code></td></tr></tbody></table><h3 id="scheduler" tabindex="-1">Scheduler <a class="header-anchor" href="#scheduler" aria-label="Permalink to &quot;Scheduler&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>ENABLE_SCHEDULER</code></td><td>Force-enable scheduler in debug mode</td><td><code>0</code></td></tr><tr><td><code>HEALTH_CHECK_INTERVAL</code></td><td>Provider health check interval (seconds)</td><td><code>300</code></td></tr><tr><td><code>BALANCE_CHECK_INTERVAL</code></td><td>Balance check interval (seconds)</td><td><code>1800</code></td></tr></tbody></table><h3 id="alerting" tabindex="-1">Alerting <a class="header-anchor" href="#alerting" aria-label="Permalink to &quot;Alerting&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>ALERT_COOLDOWN</code></td><td>Alert cooldown period (seconds)</td><td><code>300</code></td></tr></tbody></table><h3 id="admin-account" tabindex="-1">Admin Account <a class="header-anchor" href="#admin-account" aria-label="Permalink to &quot;Admin Account&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>WEBROUTER_ADMIN_USER</code></td><td>Default admin username</td><td><code>admin</code></td></tr><tr><td><code>WEBROUTER_ADMIN_PASSWORD</code></td><td>Default admin password</td><td><code>admin123456</code></td></tr></tbody></table><h2 id="demo-mode" tabindex="-1">Demo Mode <a class="header-anchor" href="#demo-mode" aria-label="Permalink to &quot;Demo Mode&quot;">​</a></h2><p>Set <code>WEBROUTER_DEMO=1</code> to enable demo mode:</p><ul><li>Auto-login with <code>demo</code> / <code>demo123456</code></li><li>Read-only protection for core data</li><li>Pre-seeded sample data (providers, tokens, alerts, request logs)</li></ul><h2 id="system-settings-admin-panel" tabindex="-1">System Settings (Admin Panel) <a class="header-anchor" href="#system-settings-admin-panel" aria-label="Permalink to &quot;System Settings (Admin Panel)&quot;">​</a></h2><p>The following settings can be configured through the admin panel under <strong>Settings</strong>:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Description</th></tr></thead><tbody><tr><td>Gateway Mode</td><td>Enable/disable wr-proxy routing</td></tr><tr><td>Smart Routing</td><td>Enable/disable auto model selection</td></tr><tr><td>Retry Count</td><td>Number of retry attempts</td></tr><tr><td>Timeout</td><td>Request timeout in seconds</td></tr><tr><td>Alert SMTP</td><td>Email server configuration</td></tr><tr><td>Alert WeChat</td><td>ServerChan SendKey for WeChat notifications</td></tr><tr><td>Alert Email</td><td>Alert notification email address</td></tr></tbody></table>',19)])])}const m=e(r,[["render",n]]);export{b as __pageData,m as default};
